div.p:
BAD (Arch-Dependent):
c
// DANGEROUS: Swaps byte logic and includes stack junk in high bytes
if ((uint64_t)a == (uint64_t)b) { ... }

GOOD (Portable):
c
// Standard library approach
if (memcmp(mac1, mac2, 6) == 0) { ... }

OPTIMIZED (Constant Time / SIMD Friendly):
c
// Bitwise unrolling (No Branching)
uint64_t diff = 0;
diff |= (mac1[0] ^ mac2[0]);
diff |= (mac1[1] ^ mac2[1]);
diff |= (mac1[2] ^ mac2[2]);
diff |= (mac1[3] ^ mac2[3]);
diff |= (mac1[4] ^ mac2[4]);
diff |= (mac1[5] ^ mac2[5]);
if (diff == 0) { /* Match */ }
